import { randomUUID } from "node:crypto";
import { getModel } from "@mariozechner/pi-ai";
import { Type } from "@sinclair/typebox";
import {
  AuthStorage,
  createAgentSession,
  ModelRegistry,
  SessionManager,
  type ToolDefinition,
  type AgentToolResult,
} from "@mariozechner/pi-coding-agent";
import type { AgentBackend, AgentEvent, AgentResult } from "./adapters/types.js";
import { PiAdapter } from "./adapters/pi.js";
import { MockAdapter } from "./adapters/mock.js";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface MissionAgent {
  id: string;
  name: string;
  status: "idle" | "working" | "done" | "error";
  logs: { timestamp: number; message: string; type: "info" | "success" | "error" | "warning" }[];
  currentTool: string | null;
  result?: AgentResult;
}

export interface MissionState {
  missionId: string;
  status: "running" | "complete" | "error" | "idle";
  agents: Map<string, MissionAgent>;
  summary?: string;
}

type Broadcast = (msg: Record<string, unknown>) => void;

// ---------------------------------------------------------------------------
// Adapter selection
// ---------------------------------------------------------------------------

function getAdapter(backendName?: string): AgentBackend {
  if (!process.env.OPENROUTER_API_KEY) return new MockAdapter();
  if (backendName === "mock") return new MockAdapter();
  return new PiAdapter();
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const MAX_CONCURRENT_AGENTS = Number(process.env.MAX_CONCURRENT_AGENTS ?? 5);
const AGENT_TIMEOUT_MS = Number(process.env.AGENT_TIMEOUT_MS ?? 5 * 60 * 1000);

const ORCHESTRATOR_SYSTEM_PROMPT = `You are a software factory orchestrator. You receive a task from the user and break it down into work for sub-agents. Each sub-agent is a full coding agent that can read, write, edit files and run commands in the repository.

Rules:
- Break the task into parallel work when possible using spawn_agents
- Give each agent a clear, specific task description
- Never assign two agents work on the same file. Separate agents by file/directory scope.
- Review agent results and spawn more agents if needed
- When all work is done, summarize what was accomplished`;

// ---------------------------------------------------------------------------
// Mission runner
// ---------------------------------------------------------------------------

let currentMission: MissionState | null = null;
let missionAbortController: AbortController | null = null;

export function getCurrentMission(): MissionState | null {
  return currentMission;
}

export async function startMission(
  prompt: string,
  broadcast: Broadcast,
  backendName?: string,
): Promise<void> {
  if (currentMission?.status === "running") {
    broadcast({ type: "mission_error", message: "A mission is already running" });
    return;
  }

  const missionId = randomUUID().slice(0, 8);
  const adapter = getAdapter(backendName);
  missionAbortController = new AbortController();

  currentMission = {
    missionId,
    status: "running",
    agents: new Map(),
  };

  broadcast({ type: "mission_started", missionId });
  console.log(`[mission] Started mission ${missionId} with ${adapter.name} backend`);

  try {
    const summary = await runOrchestrator(prompt, adapter, broadcast, missionAbortController.signal);
    currentMission.status = "complete";
    currentMission.summary = summary;
    broadcast({ type: "mission_complete", summary });
    console.log(`[mission] Mission ${missionId} complete`);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    currentMission.status = "error";
    broadcast({ type: "mission_error", message: msg });
    console.error(`[mission] Mission ${missionId} error:`, msg);
  }
}

export function abortMission(broadcast: Broadcast): void {
  if (!currentMission || currentMission.status !== "running") return;
  missionAbortController?.abort();
  currentMission.status = "error";
  broadcast({ type: "mission_error", message: "Mission aborted by user" });
  console.log(`[mission] Mission ${currentMission.missionId} aborted`);
}

// ---------------------------------------------------------------------------
// Orchestrator session (bypasses adapter, uses pi SDK directly)
// ---------------------------------------------------------------------------

async function runOrchestrator(
  userPrompt: string,
  adapter: AgentBackend,
  broadcast: Broadcast,
  signal: AbortSignal,
): Promise<string> {
  const cwd = process.env.FACTORY_REPO_PATH ?? process.cwd();

  // If no API key, run a simple mock orchestrator
  if (!process.env.OPENROUTER_API_KEY) {
    return runMockOrchestrator(userPrompt, adapter, broadcast, signal, cwd);
  }

  const modelId = process.env.ORCHESTRATOR_MODEL ?? "anthropic/claude-sonnet-4";
  const model = getModel("openrouter", modelId as any);
  if (!model) throw new Error(`Orchestrator model ${modelId} not found`);

  const authStorage = AuthStorage.create();
  const modelRegistry = ModelRegistry.create(authStorage);

  let round = 0;

  const SpawnAgentsParams = Type.Object({
    agents: Type.Array(
      Type.Object({
        name: Type.String({ description: "Short name for this agent (e.g. 'Setup', 'Frontend', 'Tests')" }),
        task: Type.String({ description: "Detailed task description for the agent" }),
      }),
      { description: "Array of agents to spawn" },
    ),
  });

  const spawnAgentsTool: ToolDefinition = {
    name: "spawn_agents",
    label: "Spawn Agents",
    description: "Spawn one or more coding agents to work on tasks in parallel. Each agent can read, write, edit files and run commands.",
    parameters: SpawnAgentsParams,
    execute: async (_toolCallId, params, _signal, _onUpdate, _ctx) => {
      const args = params as { agents: { name: string; task: string }[] };
      round++;
      const agentDefs = args.agents.slice(0, MAX_CONCURRENT_AGENTS);

      broadcast({
        type: "orchestrator_spawning",
        round,
        agents: agentDefs.map((a) => ({ id: randomUUID().slice(0, 8), name: a.name })),
      });

      const results = await runAgentBatch(agentDefs, adapter, broadcast, signal, cwd);
      const resultText = JSON.stringify(results);

      return {
        content: [{ type: "text", text: resultText }],
        details: results,
      } as AgentToolResult<any>;
    },
  };

  const { session } = await createAgentSession({
    model,
    thinkingLevel: "low",
    cwd,
    customTools: [spawnAgentsTool],
    authStorage,
    modelRegistry,
    sessionManager: SessionManager.inMemory(),
  });

  if (signal.aborted) {
    session.abort();
    throw new Error("Aborted");
  }
  signal.addEventListener("abort", () => session.abort());

  // Subscribe to orchestrator events
  const unsub = session.subscribe((event: any) => {
    if (event.type === "message_start") {
      broadcast({ type: "orchestrator_thinking" });
    }
  });

  try {
    await session.prompt(userPrompt);
    // Wait for agent_end
    await new Promise<void>((resolve) => {
      const u = session.subscribe((e: any) => {
        if (e.type === "agent_end") { u(); resolve(); }
      });
    });
  } finally {
    unsub();
  }

  return currentMission?.summary ?? "Mission complete";
}

// ---------------------------------------------------------------------------
// Mock orchestrator (no API key)
// ---------------------------------------------------------------------------

async function runMockOrchestrator(
  userPrompt: string,
  adapter: AgentBackend,
  broadcast: Broadcast,
  signal: AbortSignal,
  cwd: string,
): Promise<string> {
  console.log(`[mission] Mock orchestrator analyzing: "${userPrompt.slice(0, 80)}..."`);
  broadcast({ type: "orchestrator_thinking" });
  await delay(2000);

  // Mock: generate 2-3 agents based on the prompt
  const mockAgents = [
    { name: "Scaffolder", task: `Set up the project structure for: ${userPrompt}` },
    { name: "Implementer", task: `Implement the core logic for: ${userPrompt}` },
  ];
  if (userPrompt.toLowerCase().includes("test")) {
    mockAgents.push({ name: "Tester", task: `Write tests for: ${userPrompt}` });
  }

  broadcast({
    type: "orchestrator_spawning",
    round: 1,
    agents: mockAgents.map((a) => ({ id: randomUUID().slice(0, 8), name: a.name })),
  });

  const results = await runAgentBatch(mockAgents, adapter, broadcast, signal, cwd);

  const succeeded = results.filter((r) => r.success).length;
  return `Mock mission complete: ${succeeded}/${results.length} agents succeeded`;
}

// ---------------------------------------------------------------------------
// Agent batch runner
// ---------------------------------------------------------------------------

async function runAgentBatch(
  agentDefs: { name: string; task: string }[],
  adapter: AgentBackend,
  broadcast: Broadcast,
  parentSignal: AbortSignal,
  cwd: string,
): Promise<AgentResult[]> {
  const promises = agentDefs.map((def) =>
    runSingleAgent(def, adapter, broadcast, parentSignal, cwd),
  );
  return Promise.all(promises);
}

async function runSingleAgent(
  def: { name: string; task: string },
  adapter: AgentBackend,
  broadcast: Broadcast,
  parentSignal: AbortSignal,
  cwd: string,
): Promise<AgentResult> {
  const agentId = randomUUID().slice(0, 8);

  const agent: MissionAgent = {
    id: agentId,
    name: def.name,
    status: "idle",
    logs: [],
    currentTool: null,
  };
  currentMission?.agents.set(agentId, agent);

  // Emit spawn
  broadcast({
    type: "agent:spawn",
    payload: {
      id: agentId,
      name: def.name,
      type: "worker",
      status: "idle",
      currentStation: null,
      task: { id: randomUUID().slice(0, 8), type: "compile", description: def.task, stationId: "coding-desk", progress: 0, startedAt: Date.now() },
      x: 0,
      y: 0,
      logs: [],
    },
  });

  // Per-agent abort (timeout + parent)
  const agentAbort = new AbortController();
  const timeout = setTimeout(() => agentAbort.abort(), AGENT_TIMEOUT_MS);
  if (parentSignal.aborted) agentAbort.abort();
  parentSignal.addEventListener("abort", () => agentAbort.abort());

  agent.status = "working";
  broadcast({
    type: "agent:update",
    payload: { id: agentId, status: "working" },
  });

  try {
    const result = await adapter.runAgent({
      cwd,
      task: def.task,
      signal: agentAbort.signal,
      onEvent: (event: AgentEvent) => {
        handleAgentEvent(agentId, agent, event, broadcast);
      },
    });

    clearTimeout(timeout);
    agent.status = "done";
    agent.result = result;
    appendLog(agent, result.success ? "success" : "error", result.summary);

    broadcast({
      type: "agent:update",
      payload: { id: agentId, status: "done" },
    });

    // Remove after brief delay so frontend can show "done" state
    setTimeout(() => {
      broadcast({ type: "agent:remove", payload: { id: agentId } });
    }, 2000);

    return result;
  } catch (err) {
    clearTimeout(timeout);
    const msg = err instanceof Error ? err.message : String(err);
    agent.status = "error";
    appendLog(agent, "error", msg);

    broadcast({
      type: "agent:update",
      payload: { id: agentId, status: "done" },
    });
    broadcast({ type: "agent:remove", payload: { id: agentId } });

    return { success: false, summary: msg };
  }
}

// ---------------------------------------------------------------------------
// Event handling
// ---------------------------------------------------------------------------

function handleAgentEvent(
  agentId: string,
  agent: MissionAgent,
  event: AgentEvent,
  broadcast: Broadcast,
): void {
  switch (event.type) {
    case "thinking":
      broadcast({
        type: "agent:update",
        payload: { id: agentId, status: "working" },
      });
      break;

    case "tool_start":
      agent.currentTool = event.toolName;
      appendLog(agent, "info", formatToolStatus(event.toolName, event.args));
      broadcast({
        type: "agent:update",
        payload: {
          id: agentId,
          status: "working",
          logs: agent.logs,
        },
      });
      break;

    case "tool_end":
      agent.currentTool = null;
      break;

    case "log":
      appendLog(agent, "info", event.message);
      broadcast({
        type: "agent:update",
        payload: { id: agentId, logs: agent.logs },
      });
      break;

    case "error":
      appendLog(agent, "error", event.message);
      broadcast({
        type: "agent:update",
        payload: { id: agentId, logs: agent.logs },
      });
      break;
  }
}

function appendLog(agent: MissionAgent, type: "info" | "success" | "error" | "warning", message: string): void {
  agent.logs.push({ timestamp: Date.now(), message, type });
  // Keep last 50 logs
  if (agent.logs.length > 50) agent.logs.splice(0, agent.logs.length - 50);
}

function formatToolStatus(toolName: string, args: Record<string, unknown>): string {
  switch (toolName.toLowerCase()) {
    case "read": return `Reading ${basename(String(args.file_path ?? args.path ?? "file"))}`;
    case "write": return `Writing ${basename(String(args.file_path ?? args.path ?? "file"))}`;
    case "edit": return `Editing ${basename(String(args.file_path ?? args.path ?? "file"))}`;
    case "bash":
    case "execute": {
      const cmd = String(args.command ?? args.cmd ?? "");
      return `Running: ${cmd.length > 60 ? cmd.slice(0, 57) + "..." : cmd}`;
    }
    case "grep":
    case "glob":
    case "find": return "Searching files";
    case "ls": return "Listing directory";
    default: return `${toolName}`;
  }
}

function basename(p: string): string { return p.split("/").pop() ?? p; }
function delay(ms: number): Promise<void> { return new Promise((r) => setTimeout(r, ms)); }

/**
 * Orchestrator: manages the 4 fixed-role agents using pi-coding-agent SDK.
 *
 * Uses OpenRouter with anthropic/claude-opus-4.6 model.
 * API key is read from OPENROUTER_API_KEY env var.
 *
 * Pipeline: Planner → Coder → Tester → Reviewer → loop (self-improving)
 */

import { getModel } from "@mariozechner/pi-ai";
import {
  AuthStorage,
  createAgentSession,
  createCodingTools,
  ModelRegistry,
  SessionManager,
  type AgentSession,
} from "@mariozechner/pi-coding-agent";
import { randomUUID } from "node:crypto";
import { formatToolStatus, createBridgeHandler, emitAgentCreated, emitAgentClosed } from "./bridge.js";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface AgentRole {
  id: number;
  name: string;
  systemPrompt: string;
  /** The initial prompt to send to this agent each cycle */
  taskPrompt: string;
}

interface ManagedAgent {
  role: AgentRole;
  session: AgentSession;
  unsubscribe: () => void;
}

// ---------------------------------------------------------------------------
// Agent role definitions
// ---------------------------------------------------------------------------

export const AGENT_ROLES: AgentRole[] = [
  {
    id: 1,
    name: "Planner",
    systemPrompt: `You are a senior code quality planner working in a software factory.
Your job is to analyze the codebase thoroughly, identify issues (bugs, missing tests, 
code smells, performance problems, security issues), and create a prioritized improvement plan.

Rules:
- Be specific about file paths, line numbers, and what needs to change
- Prioritize by impact: critical bugs > security > tests > code quality > performance
- Write your plan to FACTORY_PLAN.md in the repo root
- Keep the plan actionable -- each item should be completable by a single engineer
- Limit to the top 5 most impactful improvements per cycle`,
    taskPrompt: `Analyze the codebase and create an improvement plan. 
Start by exploring the project structure, reading key files, and running any existing tests.
Write your prioritized plan to FACTORY_PLAN.md with specific, actionable items.
Focus on the most impactful improvements.`,
  },
  {
    id: 2,
    name: "Coder",
    systemPrompt: `You are a senior software engineer working in a software factory.
Your job is to implement improvements from the plan created by the Planner.

Rules:
- Read FACTORY_PLAN.md first to understand what needs to be done
- Implement the highest priority item that hasn't been completed yet
- Write clean, well-structured code following existing conventions
- Add or update tests for any code you change
- Mark completed items in FACTORY_PLAN.md when done
- If you create new files, make sure they integrate properly with the existing codebase`,
    taskPrompt: `Read FACTORY_PLAN.md and implement the highest priority improvement that hasn't been completed yet.
Follow existing code conventions. Add tests for your changes. Mark the item as done in FACTORY_PLAN.md when complete.`,
  },
  {
    id: 3,
    name: "Tester",
    systemPrompt: `You are a QA engineer working in a software factory.
Your job is to verify that recent changes work correctly and the codebase is healthy.

Rules:
- Run the existing test suite first
- Check for regressions from recent changes
- Verify that the changes match what was planned in FACTORY_PLAN.md
- If tests fail, document the failures clearly in FACTORY_TEST_REPORT.md
- Run linting and type checking if available
- Report the overall health status`,
    taskPrompt: `Run all available tests, linting, and type checking.
Verify that recent changes work correctly. Write a test report to FACTORY_TEST_REPORT.md 
including: tests passed/failed, lint issues, type errors, and overall health assessment.`,
  },
  {
    id: 4,
    name: "Reviewer",
    systemPrompt: `You are a senior code reviewer working in a software factory.
Your job is to review recent changes for quality, correctness, and best practices.

Rules:
- Review the git diff of recent changes
- Check for bugs, security issues, and anti-patterns
- Verify test coverage for changed code
- Provide constructive, specific feedback
- Write your review to FACTORY_REVIEW.md
- Include suggestions for the next improvement cycle
- Be honest about what worked well and what needs improvement`,
    taskPrompt: `Review the recent changes by examining git diffs and modified files.
Check for bugs, security issues, code quality, and test coverage.
Write your review to FACTORY_REVIEW.md with specific feedback and suggestions for the next cycle.`,
  },
];

// ---------------------------------------------------------------------------
// Mock simulation (fallback when no API key)
// ---------------------------------------------------------------------------

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

interface MockTool {
  toolName: string;
  args: Record<string, unknown>;
  duration: number;
}

const MOCK_TOOLS: Record<string, MockTool[]> = {
  Planner: [
    { toolName: "read", args: { file_path: "src/index.ts" }, duration: 1200 },
    { toolName: "read", args: { file_path: "src/utils.ts" }, duration: 900 },
    { toolName: "grep", args: { pattern: "TODO|FIXME|HACK" }, duration: 1500 },
    { toolName: "bash", args: { command: "npm test -- --reporter=json" }, duration: 2000 },
    { toolName: "write", args: { file_path: "FACTORY_PLAN.md" }, duration: 1800 },
  ],
  Coder: [
    { toolName: "read", args: { file_path: "FACTORY_PLAN.md" }, duration: 800 },
    { toolName: "read", args: { file_path: "src/utils.ts" }, duration: 700 },
    { toolName: "edit", args: { file_path: "src/utils.ts" }, duration: 2500 },
    { toolName: "write", args: { file_path: "src/helpers.ts" }, duration: 2000 },
    { toolName: "task", args: { description: "Refactor error handling" }, duration: 3000 },
    { toolName: "write", args: { file_path: "src/__tests__/utils.test.ts" }, duration: 1800 },
  ],
  Tester: [
    { toolName: "bash", args: { command: "npm test" }, duration: 3000 },
    { toolName: "read", args: { file_path: "test-results.json" }, duration: 500 },
    { toolName: "bash", args: { command: "npm run lint" }, duration: 2000 },
    { toolName: "bash", args: { command: "npm run typecheck" }, duration: 1800 },
    { toolName: "write", args: { file_path: "FACTORY_TEST_REPORT.md" }, duration: 1200 },
  ],
  Reviewer: [
    { toolName: "bash", args: { command: "git diff HEAD~1" }, duration: 1200 },
    { toolName: "read", args: { file_path: "src/utils.ts" }, duration: 800 },
    { toolName: "read", args: { file_path: "src/helpers.ts" }, duration: 700 },
    { toolName: "read", args: { file_path: "FACTORY_TEST_REPORT.md" }, duration: 600 },
    { toolName: "write", args: { file_path: "FACTORY_REVIEW.md" }, duration: 2200 },
  ],
};

async function simulateAgent(
  role: AgentRole,
  broadcast: (msg: Record<string, unknown>) => void,
): Promise<void> {
  broadcast({ type: "agentCreated", id: role.id, folderName: role.name });
  await sleep(300);
  broadcast({ type: "agentStatus", id: role.id, status: "active" });
  broadcast({ type: "agentToolsClear", id: role.id });

  const tools = MOCK_TOOLS[role.name] ?? [];
  for (const tool of tools) {
    const toolId = randomUUID();
    const status = formatToolStatus(tool.toolName, tool.args);
    broadcast({ type: "agentToolStart", id: role.id, toolId, status });
    await sleep(tool.duration);
    broadcast({ type: "agentToolDone", id: role.id, toolId });
    await sleep(200);
  }

  broadcast({ type: "agentToolsClear", id: role.id });
  broadcast({ type: "agentStatus", id: role.id, status: "waiting" });
}

// ---------------------------------------------------------------------------
// Real pi-coding-agent integration
// ---------------------------------------------------------------------------

async function createPiAgent(
  role: AgentRole,
  repoPath: string,
  broadcast: (msg: Record<string, unknown>) => void,
): Promise<ManagedAgent> {
  console.log(`[orchestrator] Creating pi session for ${role.name} (id=${role.id})...`);
  const model = getModel("openrouter", "anthropic/claude-opus-4.6");
  if (!model) throw new Error("Model anthropic/claude-opus-4.6 not found");

  const authStorage = AuthStorage.create();
  const modelRegistry = ModelRegistry.create(authStorage);

  const { session } = await createAgentSession({
    model,
    thinkingLevel: "low",
    cwd: repoPath,
    tools: createCodingTools(repoPath),
    authStorage,
    modelRegistry,
    sessionManager: SessionManager.inMemory(),
  });
  console.log(`[orchestrator] Pi session created for ${role.name} (id=${role.id})`);

  // Subscribe to events and bridge to pixel-agents protocol
  const bridgeHandler = createBridgeHandler(role.id, broadcast);
  const unsubscribe = session.subscribe((event: any) => {
    if (event.type === "tool_execution_start") {
      console.log(`[bridge] Agent ${role.id} (${role.name}) TOOL: ${event.toolName}(${JSON.stringify(event.args ?? {}).slice(0, 120)})`);
    } else if (event.type !== "message_update") {
      console.log(`[bridge] Agent ${role.id} (${role.name}) event: ${event.type}`);
    }
    bridgeHandler(event);
  });

  return { role, session, unsubscribe };
}

async function runPiAgent(
  agent: ManagedAgent,
  broadcast: (msg: Record<string, unknown>) => void,
): Promise<void> {
  emitAgentCreated(agent.role.id, broadcast, agent.role.name);
  await sleep(300);

  try {
    const fullPrompt = `${agent.role.systemPrompt}\n\n${agent.role.taskPrompt}`;
    await agent.session.prompt(fullPrompt);
    await waitForIdle(agent.session);
  } catch (err) {
    console.error(`[orchestrator] Agent ${agent.role.name} error:`, err);
    broadcast({ type: "agentToolsClear", id: agent.role.id });
    broadcast({ type: "agentStatus", id: agent.role.id, status: "waiting" });
  }
}

function waitForIdle(session: AgentSession): Promise<void> {
  return new Promise((resolve) => {
    const unsub = session.subscribe((event: any) => {
      if (event.type === "agent_end") {
        unsub();
        resolve();
      }
    });
  });
}

// ---------------------------------------------------------------------------
// Dynamic agent management
// ---------------------------------------------------------------------------

let nextDynamicId = 100;

interface TrackedAgent {
  role: AgentRole;
  cancel: () => void;
  managed?: ManagedAgent;
}

const dynamicAgents = new Map<number, TrackedAgent>();

/**
 * Returns the list of available role names.
 */
export function getAvailableRoles(): string[] {
  return AGENT_ROLES.map((r) => r.name);
}

/**
 * Spawn a new agent by role name. Runs in the background (fire-and-forget).
 * Returns the newly assigned agent ID.
 */
export async function spawnAgent(
  roleName: string,
  broadcast: (msg: Record<string, unknown>) => void,
): Promise<number> {
  const role = AGENT_ROLES.find((r) => r.name === roleName);
  if (!role) {
    throw new Error(`Unknown role: ${roleName}`);
  }

  const agentId = nextDynamicId++;
  // Create a virtual role with the dynamic ID
  const dynamicRole: AgentRole = { ...role, id: agentId };

  let cancelled = false;
  const cancel = () => {
    cancelled = true;
  };

  dynamicAgents.set(agentId, { role: dynamicRole, cancel });

  const apiKey = process.env.OPENROUTER_API_KEY;

  if (!apiKey) {
    // Mock mode — fire and forget
    simulateAgent(dynamicRole, broadcast).catch((err) => {
      console.error(`[orchestrator] Dynamic agent ${agentId} (${roleName}) error:`, err);
    });
  } else {
    // Real mode — create a pi agent session and run in the background
    const repoPath = process.env.FACTORY_REPO_PATH ?? process.cwd();
    createPiAgent(dynamicRole, repoPath, broadcast)
      .then((agent) => {
        const tracked = dynamicAgents.get(agentId);
        if (tracked) {
          tracked.managed = agent;
        } else {
          // Already killed before session was created
          agent.unsubscribe();
          return;
        }
        return runPiAgent(agent, broadcast);
      })
      .catch((err) => {
        console.error(`[orchestrator] Dynamic agent ${agentId} (${roleName}) error:`, err);
      });
  }

  emitAgentCreated(agentId, broadcast, roleName);
  broadcast({ type: "agentStatus", id: agentId, status: "active" });
  console.log(`[orchestrator] Spawned dynamic agent ${agentId} (${roleName})`);
  return agentId;
}

/**
 * Kill a dynamically spawned agent by ID.
 */
export function killAgent(
  agentId: number,
  broadcast: (msg: Record<string, unknown>) => void,
): void {
  const tracked = dynamicAgents.get(agentId);
  if (tracked) {
    tracked.cancel();
    if (tracked.managed) {
      tracked.managed.unsubscribe();
      try {
        tracked.managed.session.abort();
      } catch {
        // session may not support abort, that's ok
      }
    }
    dynamicAgents.delete(agentId);
    console.log(`[orchestrator] Killed dynamic agent ${agentId} (${tracked.role.name})`);
  } else {
    console.warn(`[orchestrator] killAgent: no tracked agent with id ${agentId}`);
  }
  emitAgentClosed(agentId, broadcast);
}

