/**
 * Start the factory orchestrator.
 *
 * If OPENROUTER_API_KEY is set, uses real pi-coding-agent sessions.
 * Otherwise, runs in mock/simulation mode for demo purposes.
 */
export async function startFactory(
  broadcast: (msg: Record<string, unknown>) => void,
  repoPath?: string,
): Promise<void> {
  const apiKey = process.env.OPENROUTER_API_KEY;
  const targetRepo = repoPath ?? process.env.FACTORY_REPO_PATH ?? process.cwd();

  if (!apiKey) {
    console.log("[orchestrator] No OPENROUTER_API_KEY set — running in mock/simulation mode");
    console.log("[orchestrator] Set OPENROUTER_API_KEY to use real pi-coding-agent");
    await runMockLoop(broadcast);
    return;
  }

  console.log(`[orchestrator] Starting real factory on: ${targetRepo}`);
  console.log(`[orchestrator] Using model: openrouter/anthropic/claude-opus-4.6`);
  await runRealLoop(broadcast, targetRepo);
}

async function runMockLoop(
  broadcast: (msg: Record<string, unknown>) => void,
): Promise<void> {
  console.log("[orchestrator] Starting mock factory simulation...");

  while (true) {
    for (const role of AGENT_ROLES) {
      activeAgentIds = AGENT_ROLES.map((r) => r.id);
      console.log(`[orchestrator] Agent ${role.id} (${role.name}) starting...`);
      await simulateAgent(role, broadcast);
      console.log(`[orchestrator] Agent ${role.id} (${role.name}) finished.`);
      await sleep(1500);
    }
    console.log("[orchestrator] Full cycle complete. Restarting in 3s...");
    await sleep(3000);
  }
}

async function runRealLoop(
  broadcast: (msg: Record<string, unknown>) => void,
  repoPath: string,
): Promise<void> {
  console.log("[orchestrator] Starting real factory pipeline...");
  let cycle = 1;

  while (true) {
    console.log(`[orchestrator] === Cycle ${cycle} ===`);

    for (const role of AGENT_ROLES) {
      activeAgentIds = AGENT_ROLES.map((r) => r.id);
      console.log(`[orchestrator] Agent ${role.id} (${role.name}) starting...`);

      try {
        const agent = await createPiAgent(role, repoPath, broadcast);
        await runPiAgent(agent, broadcast);
        agent.unsubscribe();
        console.log(`[orchestrator] Agent ${role.id} (${role.name}) finished.`);
      } catch (err) {
        console.error(`[orchestrator] Agent ${role.name} failed:`, err);
        broadcast({ type: "agentStatus", id: role.id, status: "waiting" });
      }

      await sleep(2000);
    }

    cycle++;
    console.log(`[orchestrator] Cycle ${cycle - 1} complete. Starting cycle ${cycle} in 5s...`);
    await sleep(5000);
  }
}

import { createServer as createHttpServer } from "node:http";
import { WebSocketServer, WebSocket } from "ws";

export interface ServerHandle {
  /** Broadcast a message to all connected WebSocket clients. */
  broadcast: (msg: Record<string, unknown>) => void;
  /** Set of currently connected clients. */
  clients: Set<WebSocket>;
  /** Shut down the server. */
  close: () => void;
}

/**
 * Creates an HTTP + WebSocket server.
 *
 * - HTTP server on the given port (default 3001).
 * - WebSocket upgrade handler.
 * - Broadcasts JSON messages to all connected clients.
 * - Receives messages from the frontend and logs them (handlers can be added later).
 */
export function createServer(
  port: number,
  options?: {
    /** Called when a frontend sends a message to the backend. */
    onClientMessage?: (ws: WebSocket, msg: Record<string, unknown>) => void;
    /** Called when a new client connects (send initial state here). */
    onClientConnect?: (ws: WebSocket) => void;
  },
): ServerHandle {
  const httpServer = createHttpServer((_req, res) => {
    // Simple health-check endpoint
    res.writeHead(200, {
      "Content-Type": "application/json",
      "Access-Control-Allow-Origin": "*",
    });
    res.end(JSON.stringify({ status: "ok" }));
  });

  const wss = new WebSocketServer({ server: httpServer });

  const clients = new Set<WebSocket>();

  wss.on("connection", (ws) => {
    clients.add(ws);
    console.log(`[server] Client connected (total: ${clients.size})`);

    // Notify caller so they can send initial state
    options?.onClientConnect?.(ws);

    ws.on("message", (raw) => {
      try {
        const msg = JSON.parse(raw.toString()) as Record<string, unknown>;
        console.log(`[server] Received from client:`, msg.type);
        options?.onClientMessage?.(ws, msg);
      } catch {
        console.warn("[server] Failed to parse client message");
      }
    });

    ws.on("close", () => {
      clients.delete(ws);
      console.log(`[server] Client disconnected (total: ${clients.size})`);
    });

    ws.on("error", (err) => {
      console.error("[server] WebSocket error:", err.message);
      clients.delete(ws);
    });
  });

  const broadcast = (msg: Record<string, unknown>) => {
    const data = JSON.stringify(msg);
    for (const client of clients) {
      if (client.readyState === WebSocket.OPEN) {
        client.send(data);
      }
    }
  };

  httpServer.listen(port, () => {
    console.log(`[server] WebSocket server listening on ws://localhost:${port}`);
  });

  const close = () => {
    for (const client of clients) {
      client.close();
    }
    wss.close();
    httpServer.close();
  };

  return { broadcast, clients, close };
}

/**
 * Bridge module: translates pi-agent-core events to pixel-agents frontend messages.
 *
 * The bridge subscribes to a pi Agent instance's events and emits pixel-agents
 * protocol messages via a broadcast function.
 */

/** The event shape from pi-agent-core's Agent.subscribe(). */
export interface PiAgentEvent {
  type: string;
  toolCallId?: string;
  toolName?: string;
  args?: Record<string, unknown>;
  message?: Record<string, unknown>;
  messages?: Record<string, unknown>[];
  result?: unknown;
  isError?: boolean;
  toolResults?: unknown[];
}

/**
 * Format a pi tool call into a human-readable status string for the pixel-agents UI.
 *
 * Special case: if toolName is 'task' or 'agent', the status starts with "Subtask:"
 * which triggers sub-agent character spawning in the frontend.
 */
export function formatToolStatus(toolName: string, args: Record<string, unknown> | undefined): string {
  const safeArgs = args ?? {};

  switch (toolName.toLowerCase()) {
    case "read": {
      const filename = (safeArgs.file_path ?? safeArgs.path ?? safeArgs.filePath ?? "file") as string;
      return `Reading ${basename(filename)}`;
    }
    case "write": {
      const filename = (safeArgs.file_path ?? safeArgs.path ?? safeArgs.filePath ?? "file") as string;
      return `Writing ${basename(filename)}`;
    }
    case "edit": {
      const filename = (safeArgs.file_path ?? safeArgs.path ?? safeArgs.filePath ?? "file") as string;
      return `Editing ${basename(filename)}`;
    }
    case "bash":
    case "execute": {
      const command = (safeArgs.command ?? safeArgs.cmd ?? "") as string;
      const truncated = command.length > 60 ? command.slice(0, 57) + "..." : command;
      return `Running: ${truncated}`;
    }
    case "task":
    case "agent": {
      const description = (safeArgs.description ?? safeArgs.prompt ?? safeArgs.message ?? "working...") as string;
      const truncated = description.length > 60 ? description.slice(0, 57) + "..." : description;
      return `Subtask: ${truncated}`;
    }
    case "dispatch": {
      const tasks = safeArgs.tasks as Array<Record<string, unknown>> | undefined;
      if (tasks && tasks.length > 0) {
        const first = (tasks[0].action ?? tasks[0].thread ?? "tasks") as string;
        const truncated = first.length > 40 ? first.slice(0, 37) + "..." : first;
        return `Dispatching ${tasks.length} tasks: ${truncated}`;
      }
      return "Dispatching parallel tasks";
    }
    case "grep":
    case "glob":
    case "find": {
      return "Searching files";
    }
    case "ls": {
      return "Listing directory";
    }
    default: {
      const firstArgKey = Object.keys(safeArgs)[0];
      const firstArgVal = firstArgKey ? String(safeArgs[firstArgKey]) : "";
      const label = toolName.charAt(0).toUpperCase() + toolName.slice(1);
      if (firstArgVal) {
        const truncated = firstArgVal.length > 50 ? firstArgVal.slice(0, 47) + "..." : firstArgVal;
        return `${label}: ${truncated}`;
      }
      return label;
    }
  }
}

/**
 * Create a bridge that subscribes to pi-agent-core events for a given agent
 * and emits pixel-agents protocol messages.
 *
 * @param agentId - Numeric ID for this agent in the pixel-agents UI
 * @param broadcast - Function to broadcast messages to all WebSocket clients
 * @returns An event handler compatible with pi-agent-core Agent.subscribe()
 */
export function createBridgeHandler(
  agentId: number,
  broadcast: (msg: Record<string, unknown>) => void,
): (event: PiAgentEvent) => void {
  return (event: PiAgentEvent) => {
    switch (event.type) {
      case "agent_start":
        // Note: agentCreated is sent separately when the agent is first created,
        // not on every agent_start. agent_start means a new prompt run began.
        broadcast({ type: "agentStatus", id: agentId, status: "active" });
        break;

      case "turn_start":
        broadcast({ type: "agentStatus", id: agentId, status: "active" });
        broadcast({ type: "agentToolsClear", id: agentId });
        break;

      case "message_start": {
        const thinkingId = `thinking-${agentId}-${Date.now()}`;
        broadcast({
          type: "agentToolStart",
          id: agentId,
          toolId: thinkingId,
          status: "Thinking...",
        });
        break;
      }

      case "message_end":
        broadcast({ type: "agentToolsClear", id: agentId });
        break;

      case "tool_execution_start":
        broadcast({
          type: "agentToolStart",
          id: agentId,
          toolId: event.toolCallId,
          status: formatToolStatus(event.toolName ?? "unknown", event.args),
        });
        break;

      case "tool_execution_end":
        broadcast({
          type: "agentToolDone",
          id: agentId,
          toolId: event.toolCallId,
        });
        break;

      case "turn_end":
        // Turn finished — tools are done for this turn
        break;

      case "agent_end":
        broadcast({ type: "agentToolsClear", id: agentId });
        broadcast({ type: "agentStatus", id: agentId, status: "waiting" });
        break;

      // message_start, message_update, message_end — no pixel-agents equivalent
      default:
        break;
    }
  };
}

/**
 * Emit the "agent created" message. Called once when an agent is first added.
 */
export function emitAgentCreated(
  agentId: number,
  broadcast: (msg: Record<string, unknown>) => void,
  folderName?: string,
): void {
  broadcast({ type: "agentCreated", id: agentId, folderName });
}

/**
 * Emit the "agent closed" message. Called when an agent is removed.
 */
export function emitAgentClosed(
  agentId: number,
  broadcast: (msg: Record<string, unknown>) => void,
): void {
  broadcast({ type: "agentClosed", id: agentId });
}

/** Helper to extract basename from a file path. */
function basename(filePath: string): string {
  const parts = filePath.split("/");
  return parts[parts.length - 1] ?? filePath;
}

import "dotenv/config";
import { WebSocket } from "ws";
import { createServer } from "./server.js";
import { startMission, abortMission, getCurrentMission } from "./mission.js";

const PORT = Number(process.env.PORT ?? 3001);

function sendCurrentState(ws: WebSocket): void {
  const mission = getCurrentMission();
  if (mission && mission.status === "running") {
    const agents = Array.from(mission.agents.values()).map((a) => ({
      id: a.id,
      name: a.name,
      type: "worker" as const,
      status: a.status === "working" ? "working" : a.status === "done" ? "done" : "idle",
      currentStation: null,
      task: null,
      x: 0,
      y: 0,
      logs: a.logs,
    }));

    ws.send(JSON.stringify({
      type: "mission_state",
      missionId: mission.missionId,
      status: mission.status,
      agents,
    }));
  } else {
    ws.send(JSON.stringify({
      type: "mission_state",
      missionId: null,
      status: "idle",
      agents: [],
    }));
  }
}

function handleClientMessage(_ws: WebSocket, msg: Record<string, unknown>): void {
  switch (msg.type) {
    case "start_mission": {
      const prompt = msg.prompt as string;
      if (!prompt) {
        broadcast({ type: "mission_error", message: "No prompt provided" });
        return;
      }
      const backend = msg.backend as string | undefined;
      console.log(`[index] Starting mission: "${prompt.slice(0, 80)}..."`);
      startMission(prompt, broadcast, backend).catch((err) => {
        console.error("[index] Mission error:", err);
      });
      break;
    }
    case "abort_mission":
      console.log("[index] Aborting mission");
      abortMission(broadcast);
      break;
    default:
      console.log(`[index] Unhandled message type: ${msg.type}`);
  }
}

let broadcast: (msg: Record<string, unknown>) => void;

const serverHandle = createServer(PORT, {
  onClientConnect: sendCurrentState,
  onClientMessage: handleClientMessage,
});
broadcast = serverHandle.broadcast;

console.log(`[index] Factory backend started on port ${PORT}`);
console.log(`[index] API key: ${process.env.OPENROUTER_API_KEY ? "set" : "NOT SET (mock mode)"}`);
console.log(`[index] Repo: ${process.env.FACTORY_REPO_PATH ?? process.cwd()}`);

